        // And entries(filter) returns only that file entry
        Set<DotenvEntry> fileEntries = dotenv.entries(e -> true);
        assertEquals(1, fileEntries.size());
        assertTrue(fileEntries.contains(new DotenvEntry("KEY1", "VALUE1")));
